const users = [{id: 1, status: 'active'}, {id: 2, status: 'inactive'}];
const active = users.filter(u => u.status === 'active');
console.log(active);

List<User> users = List.of(new User(1, "active"), new User(2, "inactive"));
List<User> active = users.stream()
  .filter(u -> u.status.equals("active"))
  .collect(Collectors.toList());
